1193→void ConnectionManagerImpl::ActiveStream::decodeHeaders(RequestHeaderMapSharedPtr&& headers,
  1194→                                                        bool end_stream) {
  1195→  ENVOY_STREAM_LOG(debug, "request headers complete (end_stream={}):\n{}", *this, end_stream,
  1196→                   *headers);
  1197→  // We only want to record this when reading the headers the first time, not when recreating
  1198→  // a stream.
  1199→  if (!filter_manager_.hasLastDownstreamByteReceived()) {
  1200→    filter_manager_.streamInfo().downstreamTiming().onLastDownstreamHeaderRxByteReceived(
  1201→        connection_manager_.dispatcher_->timeSource());
  1202→  }
  1203→  ScopeTrackerScopeState scope(this,
  1204→                               connection_manager_.read_callbacks_->connection().dispatcher());
  1205→  request_headers_ = std::move(headers);
  1206→  filter_manager_.requestHeadersInitialized();
  1207→  if (request_header_timer_ != nullptr) {
  1208→    request_header_timer_->disableTimer();
  1209→    request_header_timer_.reset();
  1210→  }
  1211→
  1212→  // Both shouldDrainConnectionUponCompletion() and is_head_request_ affect local replies: set them
  1213→  // as early as possible.
  1214→  const Protocol protocol = connection_manager_.codec_->protocol();
  1215→  if (HeaderUtility::shouldCloseConnection(protocol, *request_headers_)) {
  1216→    // Only mark the connection to be closed if the request indicates so. The connection might
  1217→    // already be marked so before this step, in which case if shouldCloseConnection() returns
  1218→    // false, the stream info value shouldn't be overridden.
  1219→    filter_manager_.streamInfo().setShouldDrainConnectionUponCompletion(true);
  1220→  }
  1221→
  1222→  filter_manager_.streamInfo().protocol(protocol);
  1223→
  1224→  // We end the decode here to mark that the downstream stream is complete.
  1225→  maybeRecordLastByteReceived(end_stream);
  1226→
  1227→  if (!validateHeaders()) {
  1228→    ENVOY_STREAM_LOG(debug, "request headers validation failed\n{}", *this, *request_headers_);
  1229→    return;
  1230→  }
  1231→
  1232→  // We need to snap snapped_route_config_ here as it's used in mutateRequestHeaders later.
  1233→  if (connection_manager_.config_->isRoutable()) {
  1234→    if (connection_manager_.config_->routeConfigProvider() != nullptr) {
  1235→      snapped_route_config_ = connection_manager_.config_->routeConfigProvider()->configCast();
  1236→    } else if (connection_manager_.config_->scopedRouteConfigProvider() != nullptr &&
  1237→               connection_manager_.config_->scopeKeyBuilder().has_value()) {
  1238→      snapped_scoped_routes_config_ =
  1239→          connection_manager_.config_->scopedRouteConfigProvider()->config<Router::ScopedConfig>();
  1240→      snapScopedRouteConfig();
  1241→    }
  1242→  } else {
  1243→    snapped_route_config_ = connection_manager_.config_->routeConfigProvider()->configCast();
  1244→  }
  1245→
  1246→  // Drop new requests when overloaded as soon as we have decoded the headers.
  1247→  const bool drop_request_due_to_overload =
  1248→      (connection_manager_.accept_new_http_stream_ != nullptr &&
  1249→       connection_manager_.accept_new_http_stream_->shouldShedLoad()) ||
  1250→      connection_manager_.random_generator_.bernoulli(
  1251→          connection_manager_.overload_stop_accepting_requests_ref_.value());
  1252→
  1253→  if (drop_request_due_to_overload) {
  1254→    // In this one special case, do not create the filter chain. If there is a risk of memory
  1255→    // overload it is more important to avoid unnecessary allocation than to create the filters.
  1256→    filter_manager_.skipFilterChainCreation();
  1257→    connection_manager_.stats_.named_.downstream_rq_overload_close_.inc();
