  1259→        Http::Code::ServiceUnavailable, "envoy overloaded",
  1260→        [this](Http::ResponseHeaderMap& headers) {
  1261→          if (connection_manager_.config_->appendLocalOverload()) {
  1262→            headers.addReference(Http::Headers::get().EnvoyLocalOverloaded,
  1263→                                 Http::Headers::get().EnvoyOverloadedValues.True);
  1264→          }
  1265→        },
  1266→        absl::nullopt, StreamInfo::ResponseCodeDetails::get().Overload);
